VALUES
  ('optician-moex-02659', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡處方-3.00DS/-1.75DC × 180°，但角膜散光為-1.50DC × 180°，其預期的殘餘散光為多少？', '["-3.25DC × 090°", "-3.25DC × 180°", "-0.25DC × 090°", "-0.25DC × 180°"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02660', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '驗配軟式隱形眼鏡，依最平角膜曲率選擇試片基弧，常見原則下列何者正確？', '["較其更平0.1-0.2 mm", "較其更平0.2-0.6 mm", "較其更陡0.1-0.2 mm", "較其更陡0.2-0.6 mm"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02661', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關多焦點隱形眼鏡的敘述，下列何者錯誤？', '["老花軟式隱形眼鏡的設計包含雙焦（bifocal）隱形眼鏡及同時視覺隱形眼鏡（simultaneous vision lenses）等", "同時視覺隱形眼鏡（simultaneous vision lenses）可依不同設計再區分為：非球面（aspheric）、多焦點 （multifocal）及繞射同心圓（diffractive concentric）設計等", "多焦點隱形眼鏡可使光線穿透隱形眼鏡中央與周邊時聚焦不同，使眼睛同時可看近物及遠距離", "瞳孔大小與配戴多焦點隱形眼鏡的近遠視力無關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02662', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關老花隱形眼鏡設計的敘述，下列何者錯誤？', '["單視型（monovision）是將兩眼個別矯正達到同時可清楚看到近和遠目標的方式", "單視型通常將主要眼（dominant eye）矯正至看近物清楚，另一眼非主要眼（non-dominant eye）矯正至 看遠距清楚", "以單視型的方式矯正老花，通常在低度老花或原本對遠距視力要求不高的人較能成功", "單視型會降低立體感及深度和距離感，因此晚間開車須特別小心"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02663', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關乾眼症與隱形眼鏡的敘述，下列何者錯誤？', '["配戴隱形眼鏡者較常有乾眼的症狀", "嚴重乾眼症病患可使用治療型隱形眼鏡幫助減少疼痛及上皮癒合，但須定時回診並注意感染的可能", "乾眼症病人配戴隱形眼鏡時，較易有鏡片沉積物", "乾眼症的病人，建議使用高含水量水膠隱形眼鏡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02664', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關巨大乳突結膜炎的敘述，下列何者錯誤？', '["具有巨大乳突結膜炎的病人常有配戴隱形眼鏡不適、畏光、黏液性分泌物的增加和癢的症狀", "巨大乳突結膜炎與隱形眼鏡上的沉積物刺激上瞼板結膜有關", "巨大乳突結膜炎的治療包含停戴隱形眼鏡或改戴日拋型隱形眼鏡", "含水量高的隱形眼鏡較不會有隱形眼鏡沉積物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02665', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '平時常戴著隱形眼鏡過夜，呈現右眼眼睛紅、眼睛痛、眼屎多、視力嚴重模糊等現象，建議如何安全處', '["減少配戴時數", "停用隱形眼鏡", "更換保養藥水", "建議前往眼科就診"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02666', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列有關角膜新生血管的敘述，何者正確？', '["是一種急性過敏反應", "常造成隱形眼鏡滑動過大現象", "常造成眼分泌物過多", "是角膜慢性缺氧現象，應停戴隱形眼鏡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02667', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關長期配戴硬式隱形眼鏡併發症之敘述，何者錯誤？', '["隱形眼鏡沉積物會引起視力模糊、度數的改變或乾燥不適感", "當配戴的度數有改變時，須注意是否有角膜表面弧度改變或角膜水腫的狀況", "角膜變形（corneal warpage）主要常與配戴高透氧硬式隱形眼鏡有關", "角膜變形（corneal warpage）可能由於鏡片接觸到過熱的環境或清潔鏡片時指尖過度的壓搓鏡片有關"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 43, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02668', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於隱形眼鏡配戴與細菌性角膜炎之敘述，下列何者正確？①隱形眼鏡配戴是造成細菌性角膜炎最重要', '["過夜配戴隱形眼鏡提高感染的風險", "新的材質鏡片降低感染的發生率", "僅", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 44, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
